randomProjection = method();
randomProjection Ideal := Ideal => I -> (
  c := codim I;
  if c <= 1 then error "expected codimension >= 1";
  R := ring I;
  n := numgens R;
  L := symbol L;
  S := coefficientRing R[L_0..L_(n-c)];
  M := random(R^n, R^(n-(c-1)));
  f := map(R,S, vars R * M);
  preimage(f,I)
)


